import React from "react";
import pokemon from './MockPokemons';
import PokemonList from "./PokemonList";
import { Space, Table, Tag } from 'antd';
import { Name, Base } from './Pokemon';
const columns = [
    {
      title: 'Id',
      dataIndex: 'id',
      key: 'id',
    },
    {
      title: 'Name',
      dataIndex: 'name',
      key: 'name',
      render: (name: Name) => name.english,
    },
    {
      title: 'Types',
      dataIndex: 'type',
      key: 'type',
      render: (types: string[]) => types.map(type => type).join(", "), 
    },
    {
        title: 'HP',
        dataIndex: 'base',
        key: 'hp',
        render: (base: Base) => base.HP,
      },
  ];
function PokemonsPage() {
    return (
        <>        
            <h1>Pokemons</h1>
            {/* <PokemonList pokemons={pokemon} /> */}
            <Table dataSource={pokemon} columns={columns}></Table>
        </>
    );
}

export default PokemonsPage;